() => {
  const table = document.querySelector('table.bc-table');
  if (!table) return null;
  const rows = Array.from(table.querySelectorAll('tbody tr'));
  const baseRow = rows.find(row => row.cells[0].textContent.trim() === 'ResizeObserver');
  if (!baseRow) return null;
  const chromeCell = baseRow.cells[1];
  const chromeVersion = chromeCell.textContent.trim();
  const firefoxCell = baseRow.cells[3];
  const firefoxVersion = firefoxCell.textContent.trim();
  const safariCell = baseRow.cells[5];
  const safariVersion = safariCell.textContent.trim();
  const borderBoxRow = rows.find(row => row.cells[0].textContent.trim() === 'ResizeObserverEntry: borderBoxSize');
  let safariBorderSupport = 'No';
  if (borderBoxRow) {
    const safariBorderCell = borderBoxRow.cells[5];
    const supportSpan = safariBorderCell.querySelector('span');
    if (supportSpan) {
      if (supportSpan.classList.contains('bc-supports-yes')) safariBorderSupport = 'Yes';
      else if (supportSpan.classList.contains('bc-supports-partial')) safariBorderSupport = 'Partial';
    }
  }
  return {
    chrome: chromeVersion,
    firefox: firefoxVersion,
    safari: safariVersion,
    safariBorder: safariBorderSupport
  };
}

